import{_ as t,o as a,c as r,ag as i}from"./chunks/framework.CvgP6Fyv.js";const p=JSON.parse('{"title":"Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"features/dashboard.md","filePath":"features/dashboard.md"}'),o={name:"features/dashboard.md"};function s(n,e,l,d,c,h){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="dashboard" tabindex="-1">Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;Dashboard&quot;">​</a></h1><p>The dashboard is your home base in MyCompanyDesk. It gives you an at-a-glance overview of your business finances, alerts, and quick actions.</p><h2 id="dashboard-profiles" tabindex="-1">Dashboard profiles <a class="header-anchor" href="#dashboard-profiles" aria-label="Permalink to &quot;Dashboard profiles&quot;">​</a></h2><p>MyCompanyDesk offers role-based dashboard profiles that tailor the metrics and cards shown to your needs:</p><table tabindex="0"><thead><tr><th>Profile</th><th>Focus</th></tr></thead><tbody><tr><td><strong>Owner / Director</strong></td><td>Cash flow, profitability, high-level overview</td></tr><tr><td><strong>Bookkeeper / Accountant</strong></td><td>VAT, compliance, audit trails, period locks</td></tr><tr><td><strong>AR (Invoicing)</strong></td><td>Invoice metrics, outstanding payments</td></tr><tr><td><strong>AP (Purchasing)</strong></td><td>Expense tracking, vendor management</td></tr><tr><td><strong>Freelancer</strong></td><td>Simplified invoicing and income tracking</td></tr><tr><td><strong>VAT Compliance</strong></td><td>VAT calculations, deadlines, filings</td></tr><tr><td><strong>Project-based</strong></td><td>Project profitability, time tracking</td></tr><tr><td><strong>Growth / Operations</strong></td><td>Revenue trends, customer acquisition</td></tr></tbody></table><h3 id="change-your-profile" tabindex="-1">Change your profile <a class="header-anchor" href="#change-your-profile" aria-label="Permalink to &quot;Change your profile&quot;">​</a></h3><ol><li>Open the dashboard</li><li>Click the profile selector at the top</li><li>Choose the profile that best matches your role</li></ol><p>Each profile shows different metric cards, alerts, and quick actions relevant to that role.</p><h2 id="dashboard-sections" tabindex="-1">Dashboard sections <a class="header-anchor" href="#dashboard-sections" aria-label="Permalink to &quot;Dashboard sections&quot;">​</a></h2><h3 id="alerts" tabindex="-1">Alerts <a class="header-anchor" href="#alerts" aria-label="Permalink to &quot;Alerts&quot;">​</a></h3><p>Critical items that need your attention:</p><ul><li>Overdue invoices</li><li>Upcoming VAT deadlines</li><li>Expiring contracts</li><li>Low cash flow warnings</li></ul><h3 id="key-metrics" tabindex="-1">Key metrics <a class="header-anchor" href="#key-metrics" aria-label="Permalink to &quot;Key metrics&quot;">​</a></h3><p>Summary cards showing your most important numbers:</p><ul><li>Total revenue (current period)</li><li>Outstanding invoices</li><li>Total expenses</li><li>Net profit/loss</li><li>Open quotes</li></ul><h3 id="period-selection" tabindex="-1">Period selection <a class="header-anchor" href="#period-selection" aria-label="Permalink to &quot;Period selection&quot;">​</a></h3><p>Switch between different time periods to view your metrics:</p><ul><li>This week / month / quarter / year</li><li>Custom date range</li><li>Compare with previous periods</li></ul><h3 id="quick-actions" tabindex="-1">Quick actions <a class="header-anchor" href="#quick-actions" aria-label="Permalink to &quot;Quick actions&quot;">​</a></h3><p>Shortcuts to your most common tasks:</p><ul><li>Create new invoice</li><li>Add expense</li><li>Log time entry</li><li>View reports</li></ul><h3 id="recent-activity" tabindex="-1">Recent activity <a class="header-anchor" href="#recent-activity" aria-label="Permalink to &quot;Recent activity&quot;">​</a></h3><p>A feed of recent events in your workspace:</p><ul><li>Invoices sent and paid</li><li>Expenses added</li><li>Customers created</li><li>Team member actions</li></ul><h2 id="onboarding-card" tabindex="-1">Onboarding card <a class="header-anchor" href="#onboarding-card" aria-label="Permalink to &quot;Onboarding card&quot;">​</a></h2><p>New users see an onboarding card that guides them through initial setup:</p><ol><li>Set up company information</li><li>Add first customer</li><li>Create first invoice</li></ol><p>The card tracks your progress and disappears once complete (or when manually dismissed).</p>',28)])])}const m=t(o,[["render",s]]);export{p as __pageData,m as default};
